const item = $input.first();
const body = item.json.body || item.json || {};
const allowedLanguages = new Set(['auto', 'de', 'en', 'fr', 'es', 'it', 'pt', 'nl', 'pl', 'tr', 'ru', 'uk', 'ja', 'ko', 'zh']);
const languageAliases = { deutsch: 'de', german: 'de', englisch: 'en', english: 'en', automatisch: 'auto', automatic: 'auto' };
const rawLanguage = String(body.language || body.transcriptionLanguage || body.transcription_language || 'de').trim().toLowerCase();
const language = allowedLanguages.has(languageAliases[rawLanguage] || rawLanguage) ? (languageAliases[rawLanguage] || rawLanguage) : 'de';
const rawMode = String(body.outputMode || body.output_mode || body.responseFormat || body.response_format || body.format || 'structured').trim().toLowerCase();
const outputMode = ['plain', 'text', 'txt', 'raw', 'plain_text'].includes(rawMode) ? 'plain' : 'structured';
const binaryKey = item.binary?.file ? 'file' : Object.keys(item.binary || {})[0];
if (!binaryKey) {
  throw new Error('Keine Datei im Multipart-Feld file gefunden.');
}
const binary = item.binary[binaryKey];
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const payload = {
  language,
  outputMode,
  filename: binary.fileName || binary.filename || 'audio.bin',
  data: buffer.toString('base64'),
  notes: body.notes || body.metadata || '',
};
for (let index = 1; index <= 8; index++) {
  for (const prefix of ['speakerName', 'narratorVoice']) {
    const value = body[`${prefix}${index}`] || body[`${prefix}_${index}`];
    if (value) payload[`${prefix}${index}`] = value;
  }
}
return [{ json: payload }];
